class Solution:
    def findValidPair(self, s):
        from collections import Counter
        freq = Counter(s)
        n = len(s)
        for i in range(n - 1):
            a, b = s[i], s[i + 1]
            if a == b:
                continue
            if freq[a] == int(a) and freq[b] == int(b):
                return a + b
        return ''

