class Solution:
    def findValidPair(self, s):
        counts = [0] * 10
        for ch in s:
            counts[int(ch)] += 1
        for i in range(len(s) - 1):
            a, b = s[i], s[i + 1]
            if a == b:
                continue
            da, db = int(a), int(b)
            if counts[da] == da and counts[db] == db:
                return a + b
        return ''

