var findValidPair = function(s) {
    const counts = new Array(10).fill(0);
    for (const ch of s) counts[Number(ch)]++;
    for (let i = 0; i < s.length - 1; i++) {
        const a = s[i], b = s[i + 1];
        if (a === b) continue;
        const da = Number(a), db = Number(b);
        if (counts[da] === da && counts[db] === db) return a + b;
    }
    return '';
};
